"""Transcript JSONL parser and state machine for session status detection."""

import json
import logging
from enum import Enum
from pathlib import Path

logger = logging.getLogger(__name__)


class StatusState(Enum):
    """Possible states of a Claude Code session."""

    WORKING = "working"
    AWAITING_INPUT = "awaiting_input"
    PERMISSION_REQUIRED = "permission_required"
    UNKNOWN = "unknown"


def tail_jsonl(path: Path, *, max_lines: int = 10) -> list[dict]:
    """Read the last N lines of a JSONL file efficiently.

    Seeks to near the end of the file to avoid reading the entire file.
    Returns parsed JSON objects, most recent last.
    """
    try:
        file_size = path.stat().st_size
    except OSError:
        return []

    if file_size == 0:
        return []

    # Read from near the end — estimate 2KB per line as generous upper bound
    read_size = min(file_size, max_lines * 2048)

    try:
        with open(path, "r", encoding="utf-8") as fh:
            if read_size < file_size:
                fh.seek(file_size - read_size)
                # Skip partial first line
                fh.readline()
            lines = fh.readlines()
    except OSError as exc:
        logger.debug("failed to read transcript path=%s error=%s", path, exc)
        return []

    # Parse last N lines as JSON
    entries = []
    for line in lines[-max_lines:]:
        line = line.strip()
        if not line:
            continue
        try:
            entries.append(json.loads(line))
        except json.JSONDecodeError:
            continue

    return entries


def detect_state(transcript_path: Path | None) -> StatusState:
    """Detect the current state of a session from its transcript.

    State machine:
    - Last assistant entry with stop_reason="end_turn" -> AwaitingInput
    - Last assistant with stop_reason="tool_use", no tool result -> PermissionRequired
    - Last assistant with stop_reason="tool_use", has tool result -> Working
    - Last entry is user prompt (not tool result) -> Working
    - Cannot determine -> Unknown
    """
    if transcript_path is None:
        return StatusState.UNKNOWN

    entries = tail_jsonl(transcript_path)
    if not entries:
        return StatusState.UNKNOWN

    # Find the last assistant entry
    last_assistant_idx = None
    for i in range(len(entries) - 1, -1, -1):
        if entries[i].get("type") == "assistant":
            last_assistant_idx = i
            break

    # Check if there's a user prompt AFTER the last assistant entry
    # (meaning Claude is currently processing a new prompt)
    if last_assistant_idx is not None:
        for i in range(last_assistant_idx + 1, len(entries)):
            entry = entries[i]
            if entry.get("type") == "user":
                message = entry.get("message", {})
                content = message.get("content", [])
                # A user prompt (not a tool result) means Claude is working
                if isinstance(content, list):
                    has_text = any(
                        isinstance(item, dict) and item.get("type") == "text" for item in content
                    )
                    if has_text:
                        return StatusState.WORKING

    if last_assistant_idx is None:
        # No assistant entry found — check if last entry is a user prompt
        last_entry = entries[-1]
        if last_entry.get("type") == "user":
            message = last_entry.get("message", {})
            content = message.get("content", [])
            # Check if it's a tool result (not a user prompt)
            if isinstance(content, list):
                has_tool_result = any(
                    isinstance(item, dict) and item.get("type") == "tool_result" for item in content
                )
                if has_tool_result:
                    return StatusState.UNKNOWN
            return StatusState.WORKING
        return StatusState.UNKNOWN

    assistant_entry = entries[last_assistant_idx]
    message = assistant_entry.get("message", {})
    stop_reason = message.get("stop_reason", "")

    if stop_reason == "end_turn":
        return StatusState.AWAITING_INPUT

    if stop_reason == "tool_use":
        # Collect all tool_use_ids from the assistant message
        tool_use_ids: set[str] = set()
        content = message.get("content", [])
        if isinstance(content, list):
            for item in content:
                if isinstance(item, dict) and item.get("type") == "tool_use":
                    tid = item.get("id")
                    if tid:
                        tool_use_ids.add(tid)

        # Check if any subsequent entry has a tool result matching any tool_use_id
        for i in range(last_assistant_idx + 1, len(entries)):
            entry = entries[i]
            if entry.get("type") == "user":
                entry_message = entry.get("message", {})
                entry_content = entry_message.get("content", [])
                if isinstance(entry_content, list):
                    for item in entry_content:
                        if isinstance(item, dict) and item.get("type") == "tool_result":
                            result_id = item.get("tool_use_id")
                            if not tool_use_ids or result_id in tool_use_ids:
                                return StatusState.WORKING

        # No tool result found — permission is pending
        return StatusState.PERMISSION_REQUIRED

    # Unknown stop reason
    return StatusState.UNKNOWN
